import { Link, useNavigate } from "react-router-dom";
import { logoutUser } from "../api/authApi"; // API для выхода
import { useState } from "react";
import "../styles/Sidebar.css";

export default function Sidebar() {
  const [open, setOpen] = useState(true);
  const navigate = useNavigate();

  const toggleSidebar = () => setOpen(!open);

  const handleLogout = async () => {
    try {
      await logoutUser();
      navigate("/login"); // перенаправление на страницу логина
    } catch (err) {
      console.error("Ошибка выхода:", err);
    }
  };

  const handleProfile = () => {
    navigate("/profile"); // сюда можно добавить страницу профиля/настроек
  };

  return (
    <>
      <div className={`sidebar ${open ? "open" : "collapsed"}`}>
        <h2 className="logo">{open ? "Delivery AI" : "🚀"}</h2>

        <nav>
          <Link to="/admin">📊 {open && "Dashboard"}</Link>
          <Link to="/admin/users">👥 {open && "Пользователи"}</Link>
          <Link to="/admin/routes">🛣 {open && "Маршруты"}</Link>
          <Link to="/admin/weather">🌦 {open && "Погода"}</Link>
          <Link to="/admin/traffic">🚗 {open && "Пробки"}</Link>
        </nav>

        <div className="sidebar-bottom">
          <button className="sidebar-btn" onClick={handleProfile}>
            ⚙️ {open && "Профиль"}
          </button>
          <button className="sidebar-btn" onClick={handleLogout}>
            🔓 {open && "Выход"}
          </button>
        </div>
      </div>

      <button className="sidebar-toggle" onClick={toggleSidebar}>
        {open ? "❌" : "☰"}
      </button>
    </>
  );
}
